6890 // Given a StartRange, Step and MaxBECount for an expression compute a range of
6891 // values that the expression can take. Initially, the expression has a value
6892 // from StartRange and then is changed by Step up to MaxBECount times. Signed
6893 // argument defines if we treat Step as signed or unsigned.
6894 static ConstantRange getRangeForAffineARHelper(APInt Step,
6895                                                const ConstantRange &StartRange,
6896                                                const APInt &MaxBECount,
6897                                                bool Signed) {
6898   unsigned BitWidth = Step.getBitWidth();
6899   assert(BitWidth == StartRange.getBitWidth() &&
6900          BitWidth == MaxBECount.getBitWidth() && "mismatched bit widths");
6901   // If either Step or MaxBECount is 0, then the expression won't change, and we
6902   // just need to return the initial range.
6903   if (Step == 0 || MaxBECount == 0)
6904     return StartRange;
6905 
6906   // If we don't know anything about the initial value (i.e. StartRange is
6907   // FullRange), then we don't know anything about the final range either.
6908   // Return FullRange.
6909   if (StartRange.isFullSet())
6910     return ConstantRange::getFull(BitWidth);
6911 
6912   // If Step is signed and negative, then we use its absolute value, but we also
6913   // note that we're moving in the opposite direction.
6914   bool Descending = Signed && Step.isNegative();
6915 
6916   if (Signed)
6917     // This is correct even for INT_SMIN. Let's look at i8 to illustrate this:
6918     // abs(INT_SMIN) = abs(-128) = abs(0x80) = -0x80 = 0x80 = 128.
6919     // This equations hold true due to the well-defined wrap-around behavior of
6920     // APInt.
6921     Step = Step.abs();
6922 
6923   // Check if Offset is more than full span of BitWidth. If it is, the
6924   // expression is guaranteed to overflow.
6925   if (APInt::getMaxValue(StartRange.getBitWidth()).udiv(Step).ult(MaxBECount))
6926     return ConstantRange::getFull(BitWidth);
6927 
6928   // Offset is by how much the expression can change. Checks above guarantee no
6929   // overflow here.
